import React, { useState, useEffect, useMemo } from 'react';
import './App.css';
import SearchBar from './components/SearchBar';
import Filter from './components/Filter';
import ProductGrid from './components/ProductGrid';
import { Product } from './data/products';

// App component: Main application component for the Flipkart clone
// Manages state for search term and selected category
// Filters products based on search and category
// Renders the product listing page UI
function App() {
  // State for search input
  const [searchTerm, setSearchTerm] = useState('');

  // State for selected category filter
  const [selectedCategory, setSelectedCategory] = useState('All');

  // Memoized filtered products: recalculates only when dependencies change
  const filteredProducts = useMemo(() => {
    return products.filter((product: Product) => {
      // Filter by search term (case-insensitive)
      const matchesSearch = product.name.toLowerCase().includes(searchTerm.toLowerCase());

      // Filter by category
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;

      // Return true if both conditions match
      return matchesSearch && matchesCategory;
    });
  }, [searchTerm, selectedCategory]); // Dependencies for memoization

  return (
    // Main app container with Flipkart-like styling
    <div className="min-h-screen bg-gray-50">
      {/* Header section */}
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <h1 className="text-2xl font-bold text-blue-600">Flipkart Clone</h1>
        </div>
      </header>

      {/* Main content */}
      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Search and filter section */}
        <div className="mb-8 space-y-4">
          {/* Search bar */}
          <SearchBar value={searchTerm} onChange={setSearchTerm} />

          {/* Category filter */}
          <Filter
            categories={categories}
            selectedCategory={selectedCategory}
            onChange={setSelectedCategory}
          />
        </div>

        {/* Product grid */}
        <ProductGrid products={filteredProducts} />
      </main>
    </div>
  );
}

export default App;
